import { HoundApp } from 'hound/';
import type { HoundJobMap } from './gen/hound-types.ts';

const contextApp = { db: myDatabase, config: appConfig };

const app = new HoundApp<typeof contextApp, HoundJobMap>({
  db: redis,
  ctx: contextApp,
  concurrency: 25,
  auth: Deno.env.get('HOUND_TOKEN'),
  importMeta: import.meta,
  jobDirs: ['./jobs'],
  processor: { pollIntervalMs: 500 },
});

export const { hound, management, defineJob } = app;

const app = new HoundApp({
  db: redis,
  processor: {
    retry: {
      retryDelayMs: 2_000,
      retryBackoff: 'exponential',
    },
  },
});

const { management } = new HoundApp({ db: redis });

// Inspect
await management.api.jobs.find({ status: 'failed' });

// Replay one
await management.api.jobs.retry('default:jobId');
